        for (int i = 0; i < arr.length; i++)
            if (arr[i] == target) return i;
        return -1;
    }

    public int sentinelSearch(int[] original, int target) {
        // Work on a copy with one extra slot for the sentinel
        int n = original.length;
        int[] arr = Arrays.copyOf(original, n + 1);
        arr[n] = target; // place sentinel at end

        int i = 0;
        // TODO: Loop without bounds check: while(arr[i] != target) i++;
        // TODO: if i < n, return i (found in original), else return -1
        return -1;
    }

    public static void main(String[] args) {
        SentinelSearch ss = new SentinelSearch();
        int[] arr = {15, 3, 8, 22, 5, 17, 11};

        System.out.println("Regular  search 17: " + ss.regularSearch(arr, 17));
        System.out.println("Sentinel search 17: " + ss.sentinelSearch(arr, 17));
        System.out.println("Regular  search 99: " + ss.regularSearch(arr, 99));
        System.out.println("Sentinel search 99: " + ss.sentinelSearch(arr, 99));
    }
}

